import java.util.HashSet

fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val results = mutableListOf<Long>()

    for (query in queries) {
        val l = query[0].toInt()
        val r = query[1].toInt()
        val k = query[2]

        // 1. Identify removed even numbers in nums[l..r]
        val removedEvens = HashSet<Long>()
        for (i in l..r) {
            if (nums[i] % 2 == 0L) {
                removedEvens.add(nums[i])
            }
        }

        // Convert to a sorted list for potential optimization in counting, although iterating the set is fine for the binary search structure
        val removedEvensList = removedEvens.sorted()

        // 2. Find the k-th smallest remaining positive even number using Binary Search
        // We search for the smallest target value E (which must be even) such that 
        // count_remaining(E) >= k.

        // Lower bound: 2
        var low: Long = 2

        // Upper bound estimation: 2 * k + 2 * |removedEvens|. Since k <= 10^9, 
        // 2*10^9 + 2*10^5 is a safe estimate. Use a larger safe bound for Long.
        var high: Long = 3_000_000_000L + 200_000L // Sufficiently large bound

        var ansE: Long = high

        while (low <= high) {
            // Use safe mid calculation for Long
            val mid = low + (high - low) / 2

            // We are testing 'mid' as the candidate value.

            // Number of positive evens <= mid: floor(mid / 2)
            val totalEvens = mid / 2

            // Number of removed evens <= mid
            var removedCount: Long = 0

            // Efficiently count removed evens <= mid using binary search on the sorted list, 
            // or iterating since the set size is small (<= 10^5).
            for (valToRemove in removedEvensList) {
                if (valToRemove <= mid) {
                    removedCount++
                } else {
                    // Since the list is sorted, we can break early
                    break
                }
            }

            val remainingCount = totalEvens - removedCount

            if (remainingCount >= k) {
                // mid might be the answer or too high. Store it and search lower.
                ansE = mid
                high = mid - 1
            } else {
                // mid is too small. Need a larger value.
                low = mid + 1
            }
        }

        // The binary search finds the smallest number ansE such that count_remaining(ansE) >= k.
        // Since we are counting only even numbers, the actual k-th smallest even number
        // must be even. If ansE is odd, the true k-th element must be ansE - 1.
        var finalAnswer = ansE
        if (finalAnswer % 2 != 0L) {
            finalAnswer -= 1
        }

        results.add(finalAnswer)
    }

    return results.toTypedArray()
}
